  1→import React, { useState, useEffect, useRef, useCallback } from 'react';
  2→import { useNavigate, useParams } from 'react-router-dom';
  3→import { useAuth } from '../../../Context/useAuth';
  4→import { useChapter, useChapterCommentCounts } from '../hooks/useStoryData';
  5→import { saveReadingProgress } from '../../../../API/StoryApi';
  6→import { motion, AnimatePresence } from 'framer-motion';
  7→import { BeatLoader } from 'react-spinners';
  8→import ParagraphCommentLayer from './ParagraphCommentLayer';
  9→import CommentPanel from './CommentPanel';
 10→
 11→import { LexicalComposer } from '@lexical/react/LexicalComposer';
 12→import { RichTextPlugin } from '@lexical/react/LexicalRichTextPlugin';
 13→import { ContentEditable } from '@lexical/react/LexicalContentEditable';
 14→import { LexicalErrorBoundary } from '@lexical/react/LexicalErrorBoundary';
 15→import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
 16→import { HeadingNode, QuoteNode } from '@lexical/rich-text';
 17→import ImageNode from '../../HomePage/Editor/nodes/ImageNode';
 18→
 19→import './ChapterReader.css';
 20→
 21→const readerTheme = {
 22→    paragraph: 'editor-paragraph',
 23→    heading: {
 24→        h1: 'editor-heading-h1',
 25→        h2: 'editor-heading-h2',
 26→        h3: 'editor-heading-h3',
 27→    },
 28→    quote: 'editor-quote',
 29→    text: {
 30→        bold: 'editor-text-bold',
 31→        italic: 'editor-text-italic',
 32→        underline: 'editor-text-underline',
 33→    },
 34→};
 35→
 36→const ReaderContent = ({ chapter }) => {
 37→    const [editor] = useLexicalComposerContext();
 38→
 39→    useEffect(() => {
 40→        if (chapter?.content && editor) {
 41→            try {
 42→                const content = typeof chapter.content === 'string'
 43→                    ? chapter.content
 44→                    : JSON.stringify(chapter.content);
 45→                const state = editor.parseEditorState(content);
 46→                editor.setEditorState(state);
 47→            } catch (err) {
 48→                console.error('Failed to load chapter content:', err);
 49→            }
 50→            editor.setEditable(false);
 51→        }
 52→    }, [chapter?.id, editor]);
 53→
 54→    return (
 55→        <RichTextPlugin
 56→            contentEditable={<ContentEditable className="chapter-reader-content" />}
 57→            ErrorBoundary={LexicalErrorBoundary}
 58→        />
 59→    );
 60→};
 61→
 62→const ChapterReader = () => {
 63→    const { storyId, chapterId } = useParams();
 64→    const navigate = useNavigate();
 65→    const { session } = useAuth();
 66→    const token = session?.access_token;
 67→
 68→    const { data: chapter, isLoading } = useChapter(storyId, chapterId, token);
 69→    const { data: commentCounts } = useChapterCommentCounts(chapterId, token);
 70→    const progressTimerRef = useRef(null);
 71→    const scrollRef = useRef(0);
 72→    const bodyRef = useRef(null);
 73→    const [activeComment, setActiveComment] = useState(null);
 74→
 75→    // Save reading progress debounced on scroll
 76→    const saveProgress = useCallback(() => {
 77→        if (!token || !storyId || !chapterId) return;
 78→        saveReadingProgress(token, storyId, chapterId, scrollRef.current).catch(() => {});
 79→    }, [token, storyId, chapterId]);
 80→
 81→    useEffect(() => {
 82→        const handleScroll = () => {
 83→            const scrollTop = window.scrollY || document.documentElement.scrollTop;
 84→            const docHeight = document.documentElement.scrollHeight - window.innerHeight;
 85→            scrollRef.current = docHeight > 0 ? Math.min(scrollTop / docHeight, 1) : 0;
 86→
 87→            if (progressTimerRef.current) clearTimeout(progressTimerRef.current);
 88→            progressTimerRef.current = setTimeout(saveProgress, 3000);
 89→        };
 90→
 91→        window.addEventListener('scroll', handleScroll, { passive: true });
 92→        return () => {
 93→            window.removeEventListener('scroll', handleScroll);
 94→            if (progressTimerRef.current) clearTimeout(progressTimerRef.current);
 95→            // Save on unmount
 96→            saveProgress();
 97→        };
 98→    }, [saveProgress]);
 99→
100→    // Reset comment panel when chapter changes
101→    useEffect(() => {
102→        setActiveComment(null);
103→    }, [chapterId]);
104→
105→    // Scroll progress bar
106→    useEffect(() => {
107→        const bar = document.getElementById('chapter-progress-bar');
108→        if (!bar) return;
109→
110→        const updateBar = () => {
111→            const scrollTop = window.scrollY || document.documentElement.scrollTop;
112→            const docHeight = document.documentElement.scrollHeight - window.innerHeight;
113→            const pct = docHeight > 0 ? (scrollTop / docHeight) * 100 : 0;
114→            bar.style.width = `${Math.min(pct, 100)}%`;
115→        };
116→
117→        window.addEventListener('scroll', updateBar, { passive: true });
118→        return () => window.removeEventListener('scroll', updateBar);
119→    }, []);
120→
121→    const editorConfig = {
122→        namespace: 'ChapterReader',
123→        theme: readerTheme,
124→        nodes: [ImageNode, HeadingNode, QuoteNode],
125→        editable: false,
126→        onError(error) { console.error('Lexical error:', error); },
127→    };
128→
129→    if (isLoading) {
130→        return (
131→            <div className="chapter-reader">
132→                <div className="chapter-reader-loading">
133→                    <BeatLoader size={10} color="var(--text-muted)" />
134→                </div>
135→            </div>
136→        );
137→    }
138→
139→    if (!chapter) {
140→        return (
141→            <div className="chapter-reader">
142→                <p className="chapter-reader-error">Chapter not found.</p>
143→            </div>
144→        );
145→    }
146→
147→    const prevCh = chapter.prev_chapter;
148→    const nextCh = chapter.next_chapter;
149→
150→    return (
151→        <motion.div
152→            className="chapter-reader"
153→            initial={{ opacity: 0 }}
154→            animate={{ opacity: 1 }}
155→            transition={{ duration: 0.2 }}
156→        >
157→            {/* Progress bar */}
158→            <div className="chapter-progress-track">
159→                <div id="chapter-progress-bar" className="chapter-progress-fill" />
160→            </div>
161→
162→            {/* Header */}
163→            <div className="chapter-reader-header">
164→                <button
165→                    className="chapter-reader-back"
166→                    onClick={() => navigate(`/home/stories/${storyId}`)}
167→                >
168→                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="var(--text-secondary)">
169→                        <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
170→                    </svg>
171→                </button>
172→                <div className="chapter-reader-header-info">
173→                    <span className="chapter-reader-chapter-label">Chapter {chapter.chapter_number}</span>
174→                    <h1 className="chapter-reader-title">{chapter.title}</h1>
175→                </div>
176→            </div>
177→
178→            {/* Content */}
179→            <div className="chapter-reader-body" ref={bodyRef}>
180→                <LexicalComposer initialConfig={editorConfig}>
181→                    <ReaderContent chapter={chapter} />
182→                </LexicalComposer>
183→                <ParagraphCommentLayer
184→                    containerRef={bodyRef}
185→                    commentCounts={commentCounts}
186→                    onParagraphClick={setActiveComment}
187→                />
188→            </div>
189→
190→            {/* Comment Panel */}
191→            <AnimatePresence>
192→                {activeComment && (
193→                    <CommentPanel
194→                        chapterId={chapterId}
195→                        activeComment={activeComment}
196→                        onClose={() => setActiveComment(null)}
197→                    />
198→                )}
199→            </AnimatePresence>
200→
201→            {/* Navigation */}
202→            <div className="chapter-reader-nav">
203→                {prevCh ? (
204→                    <button
205→                        className="chapter-nav-btn chapter-nav-prev"
206→                        onClick={() => navigate(`/home/stories/${storyId}/chapter/${prevCh.id}`)}
207→                    >
208→                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
209→                            <path d="M15.41 7.41L14 6l-6 6 6 6 1.41-1.41L10.83 12z"/>
210→                        </svg>
211→                        <span>Ch. {prevCh.chapter_number}: {prevCh.title}</span>
212→                    </button>
213→                ) : <div />}
214→                {nextCh ? (
215→                    <button
216→                        className="chapter-nav-btn chapter-nav-next"
217→                        onClick={() => navigate(`/home/stories/${storyId}/chapter/${nextCh.id}`)}
218→                    >
219→                        <span>Ch. {nextCh.chapter_number}: {nextCh.title}</span>
220→                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
221→                            <path d="M10 6L8.59 7.41 13.17 12l-4.58 4.59L10 18l6-6z"/>
222→                        </svg>
223→                    </button>
224→                ) : <div />}
225→            </div>
226→        </motion.div>
227→    );
228→};
229→
230→export default ChapterReader;
