  1→import { useState, useEffect, useCallback, useRef } from 'react';
  2→
  3→const HOVER_LEAVE_DELAY_MS = 450;
  4→
  5→const CommentBadge = ({ count, hasComments }) => {
  6→    return (
  7→        <>
  8→            {hasComments ? (
  9→                <svg width="13" height="13" viewBox="0 0 24 24" fill="currentColor" stroke="none">
 10→                    <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
 11→                </svg>
 12→            ) : (
 13→                <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
 14→                    <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
 15→                </svg>
 16→            )}
 17→            {hasComments && <span className="pcl-badge-count">{count}</span>}
 18→        </>
 19→    );
 20→};
 21→
 22→const ParagraphCommentLayer = ({ containerRef, commentCounts, onParagraphClick }) => {
 23→    const [paragraphs, setParagraphs] = useState([]);
 24→    const [hoveredIndex, setHoveredIndex] = useState(null);
 25→    const listenersRef = useRef([]);
 26→    const leaveTimerRef = useRef(null);
 27→    const layerRef = useRef(null);
 28→    const clickedRef = useRef(false);
 29→    const prevActiveElRef = useRef(null);
 30→
 31→    const clearLeaveTimer = useCallback(() => {
 32→        if (leaveTimerRef.current) {
 33→            clearTimeout(leaveTimerRef.current);
 34→            leaveTimerRef.current = null;
 35→        }
 36→    }, []);
 37→
 38→    const scheduleLeave = useCallback((idx) => {
 39→        clearLeaveTimer();
 40→        leaveTimerRef.current = setTimeout(() => {
 41→            setHoveredIndex((prev) => prev === idx ? null : prev);
 42→        }, HOVER_LEAVE_DELAY_MS);
 43→    }, [clearLeaveTimer]);
 44→
 45→    const scanParagraphs = useCallback(() => {
 46→        const container = containerRef.current;
 47→        if (!container) return;
 48→
 49→        listenersRef.current.forEach(({ el, enter, leave, click }) => {
 50→            el.removeEventListener('mouseenter', enter);
 51→            el.removeEventListener('mouseleave', leave);
 52→            el.removeEventListener('click', click);
 53→        });
 54→        listenersRef.current = [];
 55→
 56→        const elements = container.querySelectorAll('.editor-paragraph');
 57→        const result = [];
 58→        let realIndex = 0;
 59→
 60→        elements.forEach((el) => {
 61→            const text = el.textContent.trim();
 62→            if (!text) return;
 63→
 64→            const idx = realIndex;
 65→            el.setAttribute('data-paragraph-index', idx);
 66→            const fingerprint = text.substring(0, 100);
 67→
 68→            result.push({
 69→                index: idx,
 70→                top: el.offsetTop,
 71→                height: el.offsetHeight,
 72→                text,
 73→                fingerprint,
 74→            });
 75→
 76→            const enter = () => {
 77→                clearLeaveTimer();
 78→                setHoveredIndex(idx);
 79→            };
 80→            const leave = (event) => {
 81→                // User explicitly tapped/clicked — don't auto-hide on mouseleave
 82→                if (clickedRef.current) return;
 83→
 84→                const nextTarget = event.relatedTarget;
 85→                const layer = layerRef.current;
 86→
 87→                // Prevent hide jitter when moving directly from paragraph to badge.
 88→                if (nextTarget && layer && layer.contains(nextTarget)) {
 89→                    return;
 90→                }
 91→
 92→                scheduleLeave(idx);
 93→            };
 94→            const click = () => {
 95→                clearLeaveTimer();
 96→                clickedRef.current = true;
 97→                setHoveredIndex(idx);
 98→            };
 99→            el.addEventListener('mouseenter', enter);
100→            el.addEventListener('mouseleave', leave);
101→            el.addEventListener('click', click);
102→            listenersRef.current.push({ el, enter, leave, click });
103→
104→            realIndex++;
105→        });
106→
107→        setParagraphs(result);
108→    }, [containerRef, clearLeaveTimer, scheduleLeave]);
109→
110→    useEffect(() => {
111→        const container = containerRef.current;
112→        if (!container) return;
113→
114→        const timer = setTimeout(scanParagraphs, 300);
115→
116→        const observer = new MutationObserver((mutations) => {
117→            // Ignore mutations from our own badge layer to prevent feedback loops
118→            const layer = layerRef.current;
119→            const isOwnMutation = layer && mutations.every(
120→                (m) => layer.contains(m.target)
121→            );
122→            if (isOwnMutation) return;
123→            scanParagraphs();
124→        });
125→
126→        observer.observe(container, { childList: true, subtree: true, characterData: true });
127→        window.addEventListener('resize', scanParagraphs);
128→
129→        return () => {
130→            clearTimeout(timer);
131→            clearLeaveTimer();
132→            observer.disconnect();
133→            window.removeEventListener('resize', scanParagraphs);
134→            listenersRef.current.forEach(({ el, enter, leave, click }) => {
135→                el.removeEventListener('mouseenter', enter);
136→                el.removeEventListener('mouseleave', leave);
137→                el.removeEventListener('click', click);
138→            });
139→            listenersRef.current = [];
140→        };
141→    }, [containerRef, scanParagraphs, clearLeaveTimer]);
142→
143→    // Sync .pcl-active CSS class with hoveredIndex
144→    useEffect(() => {
145→        if (prevActiveElRef.current) {
146→            prevActiveElRef.current.classList.remove('pcl-active');
147→            prevActiveElRef.current = null;
148→        }
149→
150→        if (hoveredIndex == null) {
151→            clickedRef.current = false;
152→            return;
153→        }
154→
155→        const container = containerRef.current;
156→        if (!container) return;
157→
158→        const el = container.querySelector(
159→            `.editor-paragraph[data-paragraph-index="${hoveredIndex}"]`
160→        );
161→        if (el) {
162→            el.classList.add('pcl-active');
163→            prevActiveElRef.current = el;
164→        }
165→    }, [hoveredIndex, containerRef]);
166→
167→    // Dismiss active paragraph when tapping outside content + badge layer
168→    useEffect(() => {
169→        if (!clickedRef.current) return;
170→
171→        const handleOutsideClick = (e) => {
172→            const container = containerRef.current;
173→            const layer = layerRef.current;
174→            if (
175→                (container && container.contains(e.target)) ||
176→                (layer && layer.contains(e.target))
177→            ) return;
178→
179→            clickedRef.current = false;
180→            setHoveredIndex(null);
181→        };
182→
183→        document.addEventListener('click', handleOutsideClick);
184→        return () => document.removeEventListener('click', handleOutsideClick);
185→    }, [hoveredIndex, containerRef]);
186→
187→    const handleBadgeEnter = useCallback((idx) => {
188→        clearLeaveTimer();
189→        setHoveredIndex(idx);
190→    }, [clearLeaveTimer]);
191→
192→    const handleBadgeLeave = useCallback((idx, event) => {
193→        const nextTarget = event.relatedTarget;
194→        const nextParagraph = nextTarget?.closest?.('.editor-paragraph[data-paragraph-index]');
195→
196→        // Prevent hide jitter when moving directly from badge back to the paragraph.
197→        if (nextParagraph && Number(nextParagraph.getAttribute('data-paragraph-index')) === idx) {
198→            return;
199→        }
200→
201→        scheduleLeave(idx);
202→    }, [scheduleLeave]);
203→
204→    const counts = commentCounts || {};
205→
206→    return (
207→        <div className="pcl-layer" ref={layerRef}>
208→            {paragraphs.map((p) => {
209→                const count = counts[p.index] || 0;
210→                const hasComments = count > 0;
211→                const isVisible = hoveredIndex === p.index || hasComments;
212→
213→                return (
214→                    <div
215→                        key={p.index}
216→                        className={`pcl-badge-anchor ${isVisible ? 'pcl-badge-visible' : ''}`}
217→                        style={{ top: p.top, height: p.height }}
218→                        onMouseEnter={() => handleBadgeEnter(p.index)}
219→                        onMouseLeave={(event) => handleBadgeLeave(p.index, event)}
220→                    >
221→                        <button
222→                            className={`pcl-badge ${hasComments ? 'pcl-badge-active' : ''}`}
223→                            onClick={(e) => {
224→                                e.stopPropagation();
225→                                onParagraphClick({
226→                                    paragraphIndex: p.index,
227→                                    fingerprint: p.fingerprint,
228→                                    text: p.text,
229→                                });
230→                            }}
231→                        >
232→                            <CommentBadge count={count} hasComments={hasComments} />
233→                        </button>
234→                    </div>
235→                );
236→            })}
237→        </div>
238→    );
239→};
240→
241→export default ParagraphCommentLayer;
